With.Cte:

				SELECT {{
							Fields
								-Dimension: PointsOfSale 
									--Table: PointsOfSaleCte
								-Dimension: Products 
									--Table: ProductsCte
								-WithComma
                	   }}
					   {{
							IfRequest
								-Expression: NegativeStock
									--SUM(DataBasePointOfSales.NegativeStock) AS NegativeStock
								-Expression: NegativePendingReceptions
									--SUM(DataBasePointOfSales.NegativePendingReceptions) AS NegativePendingReceptions
						}}						   
					FROM Fact.DataBasePointOfSales
					{{
                		InnerJoin 
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
								--On: PointOfSaleId-PointOfSaleId
							-Table: DataBasePointOfSales
					}}
	            	{{
	            		InnerJoin 
	            			-Dimension: Products 
	            				--Table: ProductsCte
								--On: ProductId-ProductId
							-Table: DataBasePointOfSales
	            	}}
					{{
                		GroupBy
                			-Dimension: PointsOfSale 
                				--Table: PointsOfSaleCte
	            			-Dimension: Products 
	            				--Table: ProductsCte
	            	}}

With.Query:

				SELECT 
						{{
							Fields
								-Dimension: PointsOfSale
								-Dimension: Products
								-WithComma
                		}}
						{{
							IfRequest
								-Expression: NegativeStock
									--NegativeStock
								-Expression: NegativePendingReceptions
									--NegativePendingReceptions
								-WhenRequestTotals
									--Default
										---COUNT(*) OVER () AS TotalCount
									--Expression: NegativeStock
										---SUM(NegativeStock) OVER() AS TotalNegativeStock
									--Expression: NegativePendingReceptions
										---SUM(NegativePendingReceptions) OVER() AS TotalNegativePendingReceptions
							}}
					FROM GroupedCte
					{{
                		OrderBy
                			-Dimension: PointsOfSale
	            			-Dimension: Products
	            	}}
					{{Pagination}}
